class TestCryptoExtremeOversoldBoost(unittest.TestCase):
    def test_triggers_on_extreme_oversold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 18.3}, "ETH/USD": {"today": 22.4}}}
        fired, reason = heuristic_crypto_extreme_oversold_boost(stats)
        self.assertTrue(fired)
        self.assertIn("18.3", reason)
    def test_no_trigger_btc_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 25.0}, "ETH/USD": {"today": 22.4}}}
        fired, _ = heuristic_crypto_extreme_oversold_boost(stats)
        self.assertFalse(fired)
    def test_no_trigger_eth_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 18.3}, "ETH/USD": {"today": 30.0}}}
        fired, _ = heuristic_crypto_extreme_oversold_boost(stats)
        self.assertFalse(fired)
    def test_handles_missing_rsi_snapshot(self):
        fired, _ = heuristic_crypto_extreme_oversold_boost({})
        self.assertFalse(fired)
